import anthropic, os
from datetime import datetime, timezone, timedelta

client = anthropic.Anthropic(api_key=os.environ["ANTHROPIC_ADMIN_KEY"])

def stream_audit_logs(hours: int = 1):
    since = (datetime.now(timezone.utc) - timedelta(hours=hours)).isoformat()
    after = None
    while True:
        page = client.admin.audit_logs.list(
            limit=100, start_time=since,
            **({'after': after} if after else {})
        )
        for event in page.data:
            yield event
        if not page.has_more:
            break
        after = page.last_id

for event in stream_audit_logs(hours=1):
    # Forward to Splunk / Datadog / CloudWatch Logs
    print(event.model_dump_json())
